-- Полный банк заданий для адаптивного интервью аналитика данных.
-- Активный банк: 9 модулей * 3 уровня сложности * 5 заданий = 135 заданий.
-- Задания самодостаточные: все данные, числа и структуры таблиц, необходимые
-- для ответа, указаны прямо в формулировках.

BEGIN;

INSERT INTO competencies (
    code,
    title,
    group_name,
    description,
    initial_probability
)
VALUES
    ('missing_values', 'Обработка пропущенных значений', 'Подготовка данных', 'Анализ пропусков и выбор корректного способа обработки.', 0.4500),
    ('outliers_duplicates', 'Аномалии и дубликаты', 'Подготовка данных', 'Поиск выбросов, дублей и принятие решений по очистке данных.', 0.4500),
    ('data_transformation', 'Преобразование и нормализация данных', 'Подготовка данных', 'Кодирование, масштабирование и приведение данных к единой структуре.', 0.4500),
    ('sql_databases', 'SQL и работа с базами данных', 'Подготовка данных', 'Выборки, фильтрация, агрегация, группировки и соединения таблиц.', 0.4500),
    ('descriptive_statistics', 'Описательная статистика', 'Анализ данных', 'Меры центра, разброса и первичный анализ распределений.', 0.4500),
    ('hypothesis_testing', 'Проверка статистических гипотез', 'Анализ данных', 'Формулирование гипотез, выбор критерия и интерпретация результата.', 0.4500),
    ('simple_models', 'Простые модели анализа данных', 'Анализ данных', 'Базовые модели регрессии и классификации, метрики качества.', 0.4500),
    ('data_visualization', 'Визуализация данных', 'Интерпретация результатов', 'Выбор графиков, оформление и корректная интерпретация визуализаций.', 0.4500),
    ('business_interpretation', 'Аналитическая интерпретация', 'Интерпретация результатов', 'Интерпретация структурных связей, временных зависимостей и перевод результатов анализа в бизнес-выводы.', 0.4500)
ON CONFLICT (code) DO UPDATE SET
    title = EXCLUDED.title,
    group_name = EXCLUDED.group_name,
    description = EXCLUDED.description,
    initial_probability = EXCLUDED.initial_probability,
    is_active = TRUE;

-- Перед загрузкой финального банка все прежние задания выводятся из активного
-- подбора. После загрузки незадействованные старые задания удаляются.
UPDATE tasks
SET is_active = FALSE;

WITH task_seed AS (
    SELECT *
    FROM jsonb_to_recordset($task_bank$
[
  {"competency_code":"missing_values","title":"MV-E01 - Понятие пропуска","question_text":"Что в аналитике данных обычно называют пропущенным значением?","task_type":"single_choice","difficulty":"easy","options":[{"id":"empty_or_null","label":"Отсутствующее значение в ячейке, например NULL, NA или пустая строка"},{"id":"zero","label":"Любое значение, равное нулю"},{"id":"duplicate","label":"Повторяющаяся строка в таблице"},{"id":"outlier","label":"Слишком большое числовое значение"}],"correct_answer":{"option_id":"empty_or_null"},"rubric":{"criteria":[]}},
  {"competency_code":"missing_values","title":"MV-E02 - Доля пропусков","question_text":"Какой показатель первым помогает понять масштаб проблемы пропусков в столбце?","task_type":"single_choice","difficulty":"easy","options":[{"id":"missing_share","label":"Доля пропущенных значений в столбце"},{"id":"max_value","label":"Максимальное значение столбца"},{"id":"row_order","label":"Порядковый номер первой строки"},{"id":"file_size","label":"Размер файла на диске"}],"correct_answer":{"option_id":"missing_share"},"rubric":{"criteria":[]}},
  {"competency_code":"missing_values","title":"MV-E03 - Робастное заполнение","question_text":"Чем обычно лучше заполнить пропуски в числовом признаке, если распределение сильно скошено и есть выбросы?","task_type":"single_choice","difficulty":"easy","options":[{"id":"median","label":"Медианой"},{"id":"mean","label":"Средним арифметическим без проверки выбросов"},{"id":"random_text","label":"Случайной текстовой меткой"},{"id":"max","label":"Максимальным значением"}],"correct_answer":{"option_id":"median"},"rubric":{"criteria":[]}},
  {"competency_code":"missing_values","title":"MV-E04 - Проверки перед импутацией","question_text":"Какие действия корректно выполнить перед заполнением пропусков? Выберите все подходящие варианты.","task_type":"multiple_choice","difficulty":"easy","options":[{"id":"share","label":"Оценить долю пропусков"},{"id":"pattern","label":"Проверить, связаны ли пропуски с другими признаками"},{"id":"distribution","label":"Изучить распределение признака"},{"id":"always_zero","label":"Всегда заменить пропуски нулями без анализа"}],"correct_answer":{"option_ids":["share","pattern","distribution"]},"rubric":{"criteria":[]}},
  {"competency_code":"missing_values","title":"MV-E05 - Тип пропусков и смысл","question_text":"Сопоставьте тип пропусков с кратким описанием.","task_type":"matching","difficulty":"easy","options":{"pairs":[{"id":"mcar","label":"MCAR"},{"id":"mar","label":"MAR"},{"id":"mnar","label":"MNAR"}],"matches":[{"id":"random","label":"Пропуски не связаны ни с наблюдаемыми, ни со скрытыми значениями"},{"id":"observed","label":"Вероятность пропуска объясняется другими наблюдаемыми признаками"},{"id":"hidden","label":"Пропуск связан с самим ненаблюдаемым значением"}]},"correct_answer":{"matches":{"mcar":"random","mar":"observed","mnar":"hidden"}},"rubric":{"criteria":[]}},
  {"competency_code":"missing_values","title":"MV-M01 - Небольшая доля пропусков","question_text":"В признаке age пропущено около 4% значений, распределение умеренно скошено, модель требует числовую матрицу без NULL. Какой первый способ обработки наиболее обоснован?","task_type":"single_choice","difficulty":"medium","options":[{"id":"median","label":"Заполнить медианой после проверки распределения"},{"id":"delete_column","label":"Удалить весь столбец age"},{"id":"zero","label":"Заменить все пропуски нулями"},{"id":"target","label":"Заполнить значением целевой переменной"}],"correct_answer":{"option_id":"median"},"rubric":{"criteria":[]}},
  {"competency_code":"missing_values","title":"MV-M02 - Пропуски в категории","question_text":"В столбце acquisition_channel пропуски означают, что источник привлечения не был зафиксирован системой. Какие варианты обработки можно рассмотреть?","task_type":"multiple_choice","difficulty":"medium","options":[{"id":"unknown","label":"Создать отдельную категорию unknown или not_tracked"},{"id":"mode","label":"Проверить возможность заполнения модой, если это не исказит выводы"},{"id":"indicator","label":"Добавить индикатор наличия пропуска"},{"id":"mean","label":"Заполнить средним арифметическим"}],"correct_answer":{"option_ids":["unknown","mode","indicator"]},"rubric":{"criteria":[]}},
  {"competency_code":"missing_values","title":"MV-M03 - Метод и ситуация","question_text":"Сопоставьте ситуацию с наиболее уместным первым решением.","task_type":"matching","difficulty":"medium","options":{"pairs":[{"id":"few_random","label":"1% случайных пропусков в строках"},{"id":"important_category","label":"Пропуски в важной категориальной переменной"},{"id":"time_series_gap","label":"Короткие разрывы во временном ряду"}],"matches":[{"id":"drop_rows","label":"Рассмотреть удаление строк после оценки потерь"},{"id":"unknown_indicator","label":"Добавить категорию unknown и индикатор пропуска"},{"id":"interpolate","label":"Рассмотреть интерполяцию с проверкой сезонности"}]},"correct_answer":{"matches":{"few_random":"drop_rows","important_category":"unknown_indicator","time_series_gap":"interpolate"}},"rubric":{"criteria":[]}},
  {"competency_code":"missing_values","title":"MV-M04 - Проверки revenue","question_text":"В таблице заказов есть пропуски в revenue. Опишите, какие проверки нужно выполнить перед выбором способа заполнения и почему простой ноль может исказить анализ.","task_type":"text","difficulty":"medium","options":[],"correct_answer":null,"rubric":{"criteria":["указана оценка доли пропусков","проверена связь пропусков с сегментом, датой или каналом","учтено распределение revenue и выбросы","объяснено, почему ноль может означать не отсутствие выручки, а ошибку сбора"]}},
  {"competency_code":"missing_values","title":"MV-M05 - Пропуски перед A/B анализом","question_text":"В A/B тесте у части пользователей отсутствует значение device_type, а конверсия сравнивается по устройствам. Опишите безопасный план обработки таких пропусков перед анализом.","task_type":"text","difficulty":"medium","options":[],"correct_answer":null,"rubric":{"criteria":["предложена проверка доли пропусков по группам A и B","описан риск смещения при неравномерных пропусках","предложена отдельная категория или индикатор пропуска","сделан вывод о влиянии обработки на интерпретацию конверсии"]}},
  {"competency_code":"missing_values","title":"MV-H01 - Кейс с региональными пропусками","question_text":"Кейс. В датасете интернет-магазина 50000 заказов. В поле revenue пропущено 18% значений; 70% этих пропусков приходится на регион Far East, где часть платежей проходит через отдельного провайдера. Средняя выручка нужна для отчета по регионам. Опишите, как диагностировать механизм пропусков и какой способ обработки выбрать для отчета.","task_type":"text","difficulty":"hard","options":[],"correct_answer":null,"rubric":{"criteria":["распознано, что пропуски не выглядят полностью случайными","предложена проверка по регионам, провайдерам, датам и статусам оплаты","обосновано, почему глобальная средняя может исказить региональный отчет","предложена сегментная импутация, отдельная категория качества данных или исключение с оговоркой","описано влияние выбранного решения на бизнес-вывод"]}},
  {"competency_code":"missing_values","title":"MV-H02 - Кейс с временным рядом","question_text":"Кейс. Есть дневной ряд посещений сайта за 90 дней. В таблице отсутствуют значения за 3 отдельных дня и за один непрерывный период из 8 дней после сбоя трекера. Нужно построить тренд посещаемости. Предложите разные способы обработки коротких и длинных разрывов и критерии выбора.","task_type":"text","difficulty":"hard","options":[],"correct_answer":null,"rubric":{"criteria":["разделены короткие и длинные разрывы","для коротких разрывов рассмотрена интерполяция или локальная оценка","для длинного сбоя указана необходимость маркировки или исключения периода из тренда","учтена недельная сезонность","описаны ограничения интерпретации после восстановления данных"]}},
  {"competency_code":"missing_values","title":"MV-H03 - Кейс перед моделью оттока","question_text":"Кейс. Для модели оттока есть признаки tenure, monthly_spend, support_tickets и plan_type. В monthly_spend пропущено 12% значений, причем пропуски чаще у клиентов с новым тарифом. Опишите пайплайн обработки пропусков так, чтобы не получить утечку данных и не исказить оценку качества модели.","task_type":"text","difficulty":"hard","options":[],"correct_answer":null,"rubric":{"criteria":["учтена связь пропусков с тарифом","предложено обучать импутер только на train-части","предложен индикатор пропуска","обоснован выбор медианной или групповой импутации","упомянута проверка качества модели и стабильности выводов после обработки"]}},
  {"competency_code":"missing_values","title":"MV-H04 - Риски удаления строк","question_text":"В датасете 30000 клиентов пропуски в income есть у 22% строк и чаще встречаются у молодых клиентов. Какие риски возникнут, если просто удалить все строки с пропусками?","task_type":"multiple_choice","difficulty":"hard","options":[{"id":"sample_bias","label":"Может измениться состав выборки и появиться смещение по возрасту"},{"id":"power_loss","label":"Снизится размер выборки и статистическая мощность анализа"},{"id":"target_shift","label":"Может измениться распределение целевой переменной"},{"id":"always_better","label":"Качество анализа гарантированно вырастет, потому что пропусков не останется"}],"correct_answer":{"option_ids":["sample_bias","power_loss","target_shift"]},"rubric":{"criteria":[]}},
  {"competency_code":"missing_values","title":"MV-H05 - Диагностика и действие","question_text":"Сопоставьте результат диагностики пропусков с наиболее корректным действием.","task_type":"matching","difficulty":"hard","options":{"pairs":[{"id":"group_shift","label":"Пропуски сконцентрированы в одном сегменте"},{"id":"random_small","label":"Пропусков мало и они распределены случайно"},{"id":"target_related","label":"Пропуски связаны с целевой переменной"}],"matches":[{"id":"segment_strategy","label":"Использовать сегментную стратегию и явно описать ограничение"},{"id":"simple_strategy","label":"Рассмотреть простое удаление или базовую импутацию после проверки потерь"},{"id":"leakage_check","label":"Проверить риск смещения и утечки, добавить индикатор пропуска"}]},"correct_answer":{"matches":{"group_shift":"segment_strategy","random_small":"simple_strategy","target_related":"leakage_check"}},"rubric":{"criteria":[]}},

  {"competency_code":"outliers_duplicates","title":"OD-E01 - Понятие дубликата","question_text":"Что обычно называют полным дубликатом строки в таблице?","task_type":"single_choice","difficulty":"easy","options":[{"id":"same_all_fields","label":"Строку, у которой совпадают значения всех анализируемых полей"},{"id":"same_one_field","label":"Любую строку с одинаковым значением хотя бы одного поля"},{"id":"missing_row","label":"Строку с пропуском"},{"id":"max_row","label":"Строку с максимальным числовым значением"}],"correct_answer":{"option_id":"same_all_fields"},"rubric":{"criteria":[]}},
  {"competency_code":"outliers_duplicates","title":"OD-E02 - IQR для выбросов","question_text":"Какой статистический подход часто используют для первичного поиска выбросов в числовом признаке?","task_type":"single_choice","difficulty":"easy","options":[{"id":"iqr","label":"Правило межквартильного размаха IQR"},{"id":"alphabet","label":"Сортировку названий по алфавиту"},{"id":"primary_key","label":"Проверку первичного ключа"},{"id":"join","label":"Соединение таблиц"}],"correct_answer":{"option_id":"iqr"},"rubric":{"criteria":[]}},
  {"competency_code":"outliers_duplicates","title":"OD-E03 - Не все выбросы ошибки","question_text":"Какое утверждение о выбросах является корректным?","task_type":"single_choice","difficulty":"easy","options":[{"id":"investigate","label":"Выброс нужно исследовать: он может быть ошибкой или реальным редким наблюдением"},{"id":"delete_always","label":"Любой выброс всегда надо удалить"},{"id":"ignore_always","label":"Любой выброс всегда надо игнорировать"},{"id":"fill_mean","label":"Любой выброс надо заменить средним"}],"correct_answer":{"option_id":"investigate"},"rubric":{"criteria":[]}},
  {"competency_code":"outliers_duplicates","title":"OD-E04 - Признаки проблемы качества","question_text":"Какие признаки могут указывать на проблему качества данных? Выберите все подходящие варианты.","task_type":"multiple_choice","difficulty":"easy","options":[{"id":"duplicate_ids","label":"Одинаковые идентификаторы заказов в строках, где заказ должен быть уникальным"},{"id":"negative_age","label":"Отрицательный возраст клиента"},{"id":"extreme_price","label":"Цена в 100 раз выше типичного диапазона без объяснения"},{"id":"valid_category","label":"Категория товара из утвержденного справочника"}],"correct_answer":{"option_ids":["duplicate_ids","negative_age","extreme_price"]},"rubric":{"criteria":[]}},
  {"competency_code":"outliers_duplicates","title":"OD-E05 - Проблема и проверка","question_text":"Сопоставьте проблему с первичной проверкой.","task_type":"matching","difficulty":"easy","options":{"pairs":[{"id":"duplicates","label":"Дубли заказов"},{"id":"outliers","label":"Аномально высокие значения"},{"id":"category_typos","label":"Разные написания одной категории"}],"matches":[{"id":"key_check","label":"Проверить бизнес-ключ и число повторов"},{"id":"distribution_check","label":"Посмотреть распределение и квантили"},{"id":"dictionary_check","label":"Сверить со справочником значений"}]},"correct_answer":{"matches":{"duplicates":"key_check","outliers":"distribution_check","category_typos":"dictionary_check"}},"rubric":{"criteria":[]}},
  {"competency_code":"outliers_duplicates","title":"OD-M01 - Повторы заказов","question_text":"В таблице orders поле order_id должно быть уникальным, но часть order_id встречается дважды с одинаковыми суммами и датами. Какое действие наиболее обосновано первым?","task_type":"single_choice","difficulty":"medium","options":[{"id":"check_rules","label":"Проверить бизнес-ключ, источник дублей и правило дедупликации"},{"id":"sum_all","label":"Сложить все повторяющиеся суммы без проверки"},{"id":"drop_random","label":"Удалить случайную половину таблицы"},{"id":"ignore","label":"Не проверять, потому что дубли не влияют на аналитику"}],"correct_answer":{"option_id":"check_rules"},"rubric":{"criteria":[]}},
  {"competency_code":"outliers_duplicates","title":"OD-M02 - Выбросы в цене","question_text":"В признаке price большинство значений лежит от 100 до 5000, но есть значения 999999. Какие проверки стоит выполнить?","task_type":"multiple_choice","difficulty":"medium","options":[{"id":"source","label":"Проверить источник и формат загрузки цены"},{"id":"currency","label":"Проверить валюту или масштаб единиц измерения"},{"id":"business_case","label":"Проверить, может ли значение быть реальной дорогой покупкой"},{"id":"delete_first","label":"Сразу удалить все большие значения без проверки"}],"correct_answer":{"option_ids":["source","currency","business_case"]},"rubric":{"criteria":[]}},
  {"competency_code":"outliers_duplicates","title":"OD-M03 - Метод и задача","question_text":"Сопоставьте метод с задачей контроля качества.","task_type":"matching","difficulty":"medium","options":{"pairs":[{"id":"iqr","label":"IQR"},{"id":"zscore","label":"Z-score"},{"id":"dedup_key","label":"Проверка уникального ключа"}],"matches":[{"id":"skewed_numeric","label":"Первичный поиск выбросов в скошенном числовом признаке"},{"id":"standardized_outliers","label":"Поиск экстремальных значений при близком к нормальному распределении"},{"id":"duplicate_orders","label":"Выявление повторов записей заказа"}]},"correct_answer":{"matches":{"iqr":"skewed_numeric","zscore":"standardized_outliers","dedup_key":"duplicate_orders"}},"rubric":{"criteria":[]}},
  {"competency_code":"outliers_duplicates","title":"OD-M04 - Дедупликация клиентов","question_text":"В CRM один клиент может иметь несколько строк из-за разных email, но одинакового номера телефона. Опишите, как вы построите правило поиска и объединения дублей.","task_type":"text","difficulty":"medium","options":[],"correct_answer":null,"rubric":{"criteria":["выделены возможные бизнес-ключи: телефон, email, имя, дата рождения","описана проверка точных и неточных совпадений","предложено не удалять строки без правила приоритета","указана необходимость сохранить трассировку объединения"]}},
  {"competency_code":"outliers_duplicates","title":"OD-M05 - Аномалия или сезонность","question_text":"В дневных продажах один день в 4 раза выше среднего, но это дата крупной распродажи. Объясните, почему автоматическое удаление такого значения может быть ошибкой.","task_type":"text","difficulty":"medium","options":[],"correct_answer":null,"rubric":{"criteria":["объяснено отличие ошибки данных от реального редкого события","учтен контекст распродажи или маркетинговой кампании","предложена маркировка события вместо удаления","описано влияние на средние значения и прогноз"]}},
  {"competency_code":"outliers_duplicates","title":"OD-H01 - Кейс с задвоенными заказами","question_text":"Кейс. В таблице заказов 120000 строк. Поле order_id не уникально: 3% заказов повторяются дважды. У части дублей совпадают все поля, у части отличается только updated_at, у части отличается status. Нужно подготовить данные для расчета выручки. Опишите стратегию дедупликации.","task_type":"text","difficulty":"hard","options":[],"correct_answer":null,"rubric":{"criteria":["разделены полные и частичные дубли","предложено правило выбора актуальной записи по updated_at или статусу","учтен риск двойного учета выручки","описана проверка после дедупликации","указана необходимость согласовать бизнес-правило статусов"]}},
  {"competency_code":"outliers_duplicates","title":"OD-H02 - Кейс с выбросами зарплат","question_text":"Кейс. В датасете вакансий salary_min и salary_max используются для анализа рынка. Для 2% строк salary_max выше 10000000, а часть значений, вероятно, введена в другой валюте или за год вместо месяца. Опишите, как выявить и обработать эти аномалии.","task_type":"text","difficulty":"hard","options":[],"correct_answer":null,"rubric":{"criteria":["предложены проверки валюты, периода и единиц измерения","использованы распределения и квантили по профессии или региону","описаны правила исправления, винзоризации, исключения или маркировки","учтено влияние на медиану и среднее","сформулирована проверка качества после обработки"]}},
  {"competency_code":"outliers_duplicates","title":"OD-H03 - Кейс с выбросами перед моделью","question_text":"Кейс. Для модели оценки стоимости жилья есть признаки area, rooms, price. Несколько квартир имеют area меньше 10, rooms больше 20 или price в 50 раз выше медианы района. Опишите план обработки аномалий перед обучением модели.","task_type":"text","difficulty":"hard","options":[],"correct_answer":null,"rubric":{"criteria":["предложены бизнес-правила допустимых диапазонов","учтен контекст района или сегмента жилья","разделены ошибки ввода и реальные редкие объекты","описаны варианты удаления, исправления, лог-преобразования или робастной модели","упомянута проверка влияния на метрики качества"]}},
  {"competency_code":"outliers_duplicates","title":"OD-H04 - Последствия необработанных дублей","question_text":"Какие последствия возможны, если не удалить дубли транзакций перед анализом выручки и конверсии?","task_type":"multiple_choice","difficulty":"hard","options":[{"id":"revenue_over","label":"Выручка может быть завышена"},{"id":"conversion_shift","label":"Конверсия может исказиться, если дубли связаны с покупками"},{"id":"model_leak","label":"Модель может переобучиться на повторяющихся наблюдениях"},{"id":"no_effect","label":"Дубли никогда не влияют на расчеты"}],"correct_answer":{"option_ids":["revenue_over","conversion_shift","model_leak"]},"rubric":{"criteria":[]}},
  {"competency_code":"outliers_duplicates","title":"OD-H05 - Решение по аномалии","question_text":"Сопоставьте тип обнаруженной аномалии с корректным решением.","task_type":"matching","difficulty":"hard","options":{"pairs":[{"id":"valid_promo_peak","label":"Реальный пик продаж в день акции"},{"id":"unit_error","label":"Цена записана в копейках вместо рублей"},{"id":"exact_duplicate","label":"Полный дубль строки транзакции"}],"matches":[{"id":"flag_keep","label":"Сохранить значение и добавить признак события"},{"id":"convert_units","label":"Исправить масштаб после подтверждения правила"},{"id":"deduplicate","label":"Оставить одну запись по бизнес-ключу"}]},"correct_answer":{"matches":{"valid_promo_peak":"flag_keep","unit_error":"convert_units","exact_duplicate":"deduplicate"}},"rubric":{"criteria":[]}},

  {"competency_code":"data_transformation","title":"DT-E01 - Нормализация Min-Max","question_text":"Что делает Min-Max нормализация числового признака?","task_type":"single_choice","difficulty":"easy","options":[{"id":"zero_one","label":"Преобразует значения к заданному диапазону, часто от 0 до 1"},{"id":"delete_missing","label":"Удаляет все пропуски"},{"id":"make_text","label":"Преобразует числа в произвольные строки"},{"id":"group_rows","label":"Группирует строки по категориям"}],"correct_answer":{"option_id":"zero_one"},"rubric":{"criteria":[]}},
