  {"competency_code":"sql_databases","title":"SQL-E02 - Фильтрация групп","question_text":"Какой оператор SQL используется для фильтрации результата после GROUP BY?","task_type":"single_choice","difficulty":"easy","options":[{"id":"having","label":"HAVING"},{"id":"where","label":"WHERE"},{"id":"select","label":"SELECT"},{"id":"join","label":"JOIN"}],"correct_answer":{"option_id":"having"},"rubric":{"criteria":[]}},
